      /* <flatten type="Javascript"> */
function active$VoucherFilter$(sender) {
  sender.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(sender, 'ma_bp');
  changeLookupReadonly(sender, 'ma_dvcs');
}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid;
      var dFrom = f.getItem('ngay_tu').value, dTo = f.getItem('ngay_den').value, x = f.getItem('form').selectedIndex, y = f.getItem('form').options, formName = y[x].text;
      g._alterTitle = [null, [['%f', formName, true], ['%d1', dFrom, true], ['%d2', dTo, true]]];

      var c = f.getItemValue('mau_bc') + String.fromCharCode(255) + f.getItemValue('ma_bp');
      if (!g._v) g._v = c;
      if (g._v != c) {
        remove$GridReport$Filter(g);
        g._v = c;
      }
      break;
    default:
      break;
  }
}
function initForm(f) {
  var o = f.getItem('form'), value = f._itemValue.split(String.fromCharCode(255)), text = f._itemText.split(String.fromCharCode(255)), index;
  for (var i = 0; i < value.length; i++) {
    o.options[i] = new Option(text[i], value[i]);
    if (!index && f._defaultForm == value[i]) index = i;
  }
  if (!index) index = 0;
  o.options[index].selected = true;
}
